import { useEffect, useRef, useState } from 'react'
import { useInView } from 'framer-motion'
import { useExperience } from '@/store/useExperience'

/**
 * Counts from 0 to `target` once the element scrolls into view. Returns the
 * live value plus a ref to attach to the element being observed. Honors reduced
 * motion by jumping straight to the target.
 */
export function useCountUp(target: number, durationMs = 1400) {
  const ref = useRef<HTMLSpanElement>(null)
  const inView = useInView(ref, { once: true, amount: 0.6 })
  const reducedMotion = useExperience((s) => s.reducedMotion)
  const [value, setValue] = useState(0)

  useEffect(() => {
    if (!inView) return
    if (reducedMotion) {
      setValue(target)
      return
    }

    let frame = 0
    let start: number | null = null
    const tick = (now: number) => {
      if (start === null) start = now
      const t = Math.min((now - start) / durationMs, 1)
      // easeOutCubic
      const eased = 1 - Math.pow(1 - t, 3)
      setValue(Math.round(eased * target))
      if (t < 1) frame = requestAnimationFrame(tick)
    }
    frame = requestAnimationFrame(tick)
    return () => cancelAnimationFrame(frame)
  }, [inView, reducedMotion, target, durationMs])

  return { value, ref }
}

import { useRef } from 'react'
import { AdditiveBlending, type Points } from 'three'
import { useAnimationTick } from '../animation/AnimationManager'
import { useExperience } from '@/store/useExperience'
// Reuse the registered <starsMaterial> element + its type from Starfield.
import { StarsMaterial } from './Starfield'

interface Buffers {
  positions: Float32Array
  scales: Float32Array
  phases: Float32Array
  count: number
}

function generate(count: number): Buffers {
  const positions = new Float32Array(count * 3)
  const scales = new Float32Array(count)
  const phases = new Float32Array(count)
  for (let i = 0; i < count; i++) {
    positions[i * 3] = (Math.random() - 0.5) * 16
    positions[i * 3 + 1] = (Math.random() - 0.5) * 10
    positions[i * 3 + 2] = (Math.random() - 0.5) * 12
    scales[i] = 0.3 + Math.random() * 0.9
    phases[i] = Math.random()
  }
  return { positions, scales, phases, count }
}

/**
 * Foreground dust motes drifting near the camera — adds parallax depth between
 * the viewer and the hero object. Cheap: a slow group rotation + vertical bob,
 * no per-particle CPU updates.
 */
export function Dust() {
  const quality = useExperience((s) => s.quality)
  const count = quality === 'low' ? 120 : quality === 'medium' ? 240 : 360

  const buffers = useRef<Buffers>(null)
  if (!buffers.current || buffers.current.count !== count) {
    buffers.current = generate(count)
  }
  const { positions, scales, phases } = buffers.current

  const ref = useRef<Points>(null)
  const matRef = useRef<InstanceType<typeof StarsMaterial>>(null)

  useAnimationTick(({ elapsed }) => {
    if (matRef.current) matRef.current.uTime = elapsed
    const pts = ref.current
    if (pts) {
      pts.rotation.y = elapsed * 0.03
      pts.position.y = Math.sin(elapsed * 0.2) * 0.4
    }
  })

  return (
    <points ref={ref} frustumCulled={false}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} />
        <bufferAttribute attach="attributes-aScale" args={[scales, 1]} />
        <bufferAttribute attach="attributes-aPhase" args={[phases, 1]} />
      </bufferGeometry>
      <starsMaterial
        ref={matRef}
        uSize={6}
        uColor={[0.45, 0.7, 1]}
        transparent
        depthWrite={false}
        blending={AdditiveBlending}
        fog={false}
      />
    </points>
  )
}

import { useRef } from 'react'
import { AdditiveBlending, type Points } from 'three'
import { shaderMaterial } from '@react-three/drei'
import { extend, type ThreeElement } from '@react-three/fiber'
import { useAnimationTick } from '../animation/AnimationManager'
import { useExperience } from '@/store/useExperience'
import { qualitySettings } from '../config'

/** Round, depth-attenuated, twinkling point sprites. */
export const StarsMaterial = shaderMaterial(
  { uTime: 0, uSize: 5.5, uColor: [0.7, 0.85, 1] },
  /* glsl */ `
    uniform float uTime;
    uniform float uSize;
    attribute float aScale;
    attribute float aPhase;
    varying float vTwinkle;
    void main() {
      vec4 mv = modelViewMatrix * vec4(position, 1.0);
      gl_Position = projectionMatrix * mv;
      vTwinkle = 0.55 + 0.45 * sin(uTime * 1.6 + aPhase * 6.2831);
      gl_PointSize = uSize * aScale * (320.0 / -mv.z);
    }
  `,
  /* glsl */ `
    uniform vec3 uColor;
    varying float vTwinkle;
    void main() {
      vec2 c = gl_PointCoord - 0.5;
      float d = length(c);
      float alpha = smoothstep(0.5, 0.0, d);
      gl_FragColor = vec4(uColor * (0.6 + vTwinkle), alpha * vTwinkle);
    }
  `,
)

extend({ StarsMaterial })

declare module '@react-three/fiber' {
  interface ThreeElements {
    starsMaterial: ThreeElement<typeof StarsMaterial>
  }
}

interface Buffers {
  positions: Float32Array
  scales: Float32Array
  phases: Float32Array
  count: number
}

/** Generate stars in a spherical shell (kept stable across renders via a ref). */
function generate(count: number): Buffers {
  const positions = new Float32Array(count * 3)
  const scales = new Float32Array(count)
  const phases = new Float32Array(count)
  for (let i = 0; i < count; i++) {
    // Uniform direction on a sphere, radius in a shell.
    const u = Math.random()
    const v = Math.random()
    const theta = 2 * Math.PI * u
    const phi = Math.acos(2 * v - 1)
    const r = 12 + Math.random() * 22
    positions[i * 3] = r * Math.sin(phi) * Math.cos(theta)
    positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta)
    positions[i * 3 + 2] = r * Math.cos(phi)
    scales[i] = 0.4 + Math.random() * 1.6
    phases[i] = Math.random()
  }
  return { positions, scales, phases, count }
}

export function Starfield() {
  const quality = useExperience((s) => s.quality)
  const count = quality === 'low' ? 1400 : quality === 'medium' ? 2600 : 4200

  const buffers = useRef<Buffers>(null)
  if (!buffers.current || buffers.current.count !== count) {
    buffers.current = generate(count)
  }
  const { positions, scales, phases } = buffers.current

  const pointsRef = useRef<Points>(null)
  const matRef = useRef<InstanceType<typeof StarsMaterial>>(null)

  useAnimationTick(({ elapsed }) => {
    if (matRef.current) matRef.current.uTime = elapsed
    const pts = pointsRef.current
    if (pts) {
      const { hyperdrive } = useExperience.getState()
      pts.rotation.y = elapsed * (hyperdrive ? 0.05 : 0.012)
      pts.rotation.x = Math.sin(elapsed * 0.05) * 0.05
    }
  })

  return (
    <points ref={pointsRef} frustumCulled={false}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} />
        <bufferAttribute attach="attributes-aScale" args={[scales, 1]} />
        <bufferAttribute attach="attributes-aPhase" args={[phases, 1]} />
      </bufferGeometry>
      <starsMaterial
        ref={matRef}
        uSize={qualitySettings(quality).dpr[1] * 3.2}
        transparent
        depthWrite={false}
        blending={AdditiveBlending}
        fog={false}
      />
    </points>
  )
}

import { useEffect, useRef } from 'react'
import {
  AdditiveBlending,
  Color,
  MathUtils,
  Object3D,
  type Group,
  type InstancedMesh,
  type LineSegments,
  type MeshBasicMaterial,
} from 'three'
import { useAnimationTick } from '../animation/AnimationManager'
import { useExperience } from '@/store/useExperience'
import { presenceFor } from '../world/presence'

const LAYERS = [4, 7, 7, 5]
const SPREAD_X = 5
const COLOR_BASE = new Color('#1e3a8a')
const COLOR_HOT = new Color('#22d3ee')
const HOMES = ['skills', 'research']

interface NetData {
  nodes: { x: number; y: number; z: number; layer: number }[]
  edges: Float32Array
}

function build(): NetData {
  const nodes: NetData['nodes'] = []
  const layerStart: number[] = []
  LAYERS.forEach((n, li) => {
    layerStart[li] = nodes.length
    const x = MathUtils.lerp(-SPREAD_X / 2, SPREAD_X / 2, li / (LAYERS.length - 1))
    for (let i = 0; i < n; i++) {
      const y = (i - (n - 1) / 2) * 0.85
      const z = Math.sin(i * 1.7 + li) * 0.5
      nodes.push({ x, y, z, layer: li })
    }
  })

  const edgePos: number[] = []
  for (let li = 0; li < LAYERS.length - 1; li++) {
    const a0 = layerStart[li]
    const b0 = layerStart[li + 1]
    for (let a = 0; a < LAYERS[li]; a++) {
      for (let b = 0; b < LAYERS[li + 1]; b++) {
        const na = nodes[a0 + a]
        const nb = nodes[b0 + b]
        edgePos.push(na.x, na.y, na.z, nb.x, nb.y, nb.z)
      }
    }
  }
  return { nodes, edges: new Float32Array(edgePos) }
}

/**
 * Animated MLP-style neural graph: instanced node spheres with a travelling
 * activation pulse across layers, plus additive connection lines. Cross-fades
 * in around the Skills / Research sections via the shared presence helper.
 */
export function NeuralNetwork() {
  const data = useRef<NetData>(null)
  if (!data.current) data.current = build()
  const { nodes, edges } = data.current

  const group = useRef<Group>(null)
  const inst = useRef<InstancedMesh>(null)
  const lines = useRef<LineSegments>(null)
  const presence = useRef(0)

  useEffect(() => {
    const mesh = inst.current
    if (!mesh) return
    const dummy = new Object3D()
    nodes.forEach((n, i) => {
      dummy.position.set(n.x, n.y, n.z)
      dummy.scale.setScalar(0.07)
      dummy.updateMatrix()
      mesh.setMatrixAt(i, dummy.matrix)
      mesh.setColorAt(i, COLOR_BASE)
    })
    mesh.instanceMatrix.needsUpdate = true
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true
  }, [nodes])

  useAnimationTick(({ elapsed, delta }) => {
    const { activeSection, hyperdrive } = useExperience.getState()
    const target = presenceFor(activeSection, HOMES)
    presence.current = MathUtils.damp(presence.current, target, 4, delta)
    const p = presence.current

    if (group.current) {
      group.current.visible = p > 0.01
      group.current.scale.setScalar(MathUtils.lerp(0.6, 1, p))
      group.current.rotation.y = Math.sin(elapsed * 0.15) * 0.4 + elapsed * 0.02
    }

    const mesh = inst.current
    if (mesh && p > 0.01) {
      const wave = elapsed * (hyperdrive ? 4 : 2)
      const tmp = new Color()
      nodes.forEach((n, i) => {
        const activation = 0.5 + 0.5 * Math.sin(wave - n.layer * 1.2 + n.y)
        tmp.copy(COLOR_BASE).lerp(COLOR_HOT, activation * p)
        mesh.setColorAt(i, tmp)
      })
      if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true
    }

    if (lines.current) {
      const mat = lines.current.material as MeshBasicMaterial
      mat.opacity = 0.14 * p
    }
  })

  return (
    <group ref={group} visible={false} position={[0, 0, -1]}>
      <instancedMesh ref={inst} args={[undefined, undefined, nodes.length]}>
        <sphereGeometry args={[1, 12, 12]} />
        <meshBasicMaterial toneMapped={false} fog={false} />
      </instancedMesh>

      <lineSegments ref={lines}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" args={[edges, 3]} />
        </bufferGeometry>
        <lineBasicMaterial
          color="#4d8dff"
          transparent
          opacity={0}
          blending={AdditiveBlending}
          depthWrite={false}
          fog={false}
        />
      </lineSegments>
    </group>
  )
}

import { useEffect, useRef } from 'react'
import {
  Color,
  MathUtils,
  Object3D,
  type Group,
  type InstancedMesh,
} from 'three'
import { useAnimationTick } from '../animation/AnimationManager'
import { useExperience } from '@/store/useExperience'
import { allSkills } from '@/data/skills'
import { presenceFor } from '../world/presence'

const HOMES = ['skills', 'about']
const ACCENTS = [new Color('#4d8dff'), new Color('#22d3ee'), new Color('#a855f7')]

interface Orb {
  x: number
  y: number
  z: number
  scale: number
  phase: number
}

/** Distribute skills on a Fibonacci sphere so they spread evenly. */
function build(): Orb[] {
  const n = allSkills.length
  const golden = Math.PI * (3 - Math.sqrt(5))
  return allSkills.map((skill, i) => {
    const y = 1 - (i / (n - 1)) * 2
    const radius = Math.sqrt(1 - y * y)
    const theta = golden * i
    const r = 2.3
    return {
      x: Math.cos(theta) * radius * r,
      y: y * r,
      z: Math.sin(theta) * radius * r,
      scale: 0.08 + skill.level * 0.14,
      phase: i * 0.6,
    }
  })
}

/**
 * A constellation of glowing skill orbs orbiting a shared centre — the 3D echo
 * of the DOM skills section. Each orb pulses on its own phase; the whole field
 * cross-fades in around About / Skills.
 */
export function SkillField() {
  const orbs = useRef<Orb[]>(null)
  if (!orbs.current) orbs.current = build()
  const data = orbs.current

  const group = useRef<Group>(null)
  const inst = useRef<InstancedMesh>(null)
  const presence = useRef(0)
  const dummy = useRef(new Object3D()).current

  useEffect(() => {
    const mesh = inst.current
    if (!mesh) return
    data.forEach((_, i) => {
      mesh.setColorAt(i, ACCENTS[i % ACCENTS.length])
    })
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true
  }, [data])

  useAnimationTick(({ elapsed, delta }) => {
    const { activeSection, hyperdrive } = useExperience.getState()
    const target = presenceFor(activeSection, HOMES)
    presence.current = MathUtils.damp(presence.current, target, 4, delta)
    const p = presence.current

    const mesh = inst.current
    if (!mesh) return
    group.current!.visible = p > 0.01
    if (p <= 0.01) return

    group.current!.rotation.y = elapsed * (hyperdrive ? 0.4 : 0.12)
    const beat = hyperdrive ? 5 : 2.5

    data.forEach((o, i) => {
      const pulse = 0.85 + 0.15 * Math.sin(elapsed * beat + o.phase)
      dummy.position.set(o.x, o.y, o.z)
      dummy.scale.setScalar(o.scale * pulse * MathUtils.lerp(0.2, 1, p))
      dummy.updateMatrix()
      mesh.setMatrixAt(i, dummy.matrix)
    })
    mesh.instanceMatrix.needsUpdate = true
  })

  return (
    <group ref={group} visible={false}>
      <instancedMesh ref={inst} args={[undefined, undefined, data.length]}>
        <icosahedronGeometry args={[1, 1]} />
        <meshBasicMaterial toneMapped={false} fog={false} />
      </instancedMesh>
    </group>
  )
}
